UPDATE issues
SET
    status = #{status},
    ai_decision = #{aiDecision},
    webrtc_status = #{webrtcStatus},
    reason_code = #{reasonCode}

        , resolved_at = #{resolvedAt}


        , admin_id = #{adminId}

WHERE issue_id = #{issueId}

mapper.insert:
INSERT INTO issue_images (
    issue_id, image_url
) VALUES (
    #{issueId}, #{imageUrl}
)

INSERT INTO ai_judgments (
    issue_id, image_url, ai_decision, confidence, summary
) VALUES (
    #{issueId}, #{imageUrl}, #{aiDecision}, #{confidence}, #{summary}
)

mapper.select:
SELECT DISTINCT i.issue_id AS issueId, i.issue_type AS issueType, i.status, COALESCE(i.urgency, 5) AS urgency, i.worker_id AS workerId, CASE WHEN CHAR_LENGTH(u.phone_number) >= 4 THEN CONCAT(u.name, RIGHT(u.phone_number, 4)) ELSE u.name END AS workerName, p.product_name AS productName, COALESCE(zl.location_code, '-') AS locationCode, i.created_at AS createdAt, i.resolved_at AS resolvedAt, i.admin_decision AS adminDecision, i.ai_decision AS aiDecision FROM issues i LEFT JOIN batch_task_items bti ON i.batch_task_item_id = bti.batch_task_item_id LEFT JOIN batch_tasks bt ON bt.batch_task_id = i.batch_task_id LEFT JOIN zone_locations zl ON zl.location_id = COALESCE(i.zone_location_id, i.new_location_id, bt.current_location_id, bti.location_id) LEFT JOIN users u ON i.worker_id = u.user_id LEFT JOIN products p ON bti.product_id = p.product_id WHERE i.status = #{req.status}
AND zl.zone_id = #{req.zoneId}
ORDER BY COALESCE(i.urgency, 5) ASC, i.created_at DESC
ORDER BY i.created_at DESC
ORDER BY i.resolved_at DESC
LIMIT #{req.size} OFFSET #{req.offset}

SELECT EXISTS (
    SELECT 1
    FROM issues i
    JOIN zone_locations zl ON i.zone_location_id = zl.location_id
    JOIN users admin_u ON admin_u.user_id = #{adminId}
    WHERE i.issue_id = #{issueId}
      AND zl.zone_id = admin_u.assigned_zone_id
)

SELECT i.issue_id AS issueId, i.issue_type AS issueType, i.status, p.product_name AS productName, zl.location_code AS locationCode, latest_aj.ai_decision AS aiDecision, i.admin_required AS adminRequired, i.created_at AS createdAt FROM issues i LEFT JOIN batch_task_items bti ON i.batch_task_item_id = bti.batch_task_item_id LEFT JOIN products p ON bti.product_id = p.product_id LEFT JOIN zone_locations zl ON i.zone_location_id = zl.location_id LEFT JOIN ( SELECT ai_decision, issue_id, ROW_NUMBER() OVER (PARTITION BY issue_id ORDER BY created_at DESC) as rn FROM ai_judgments ) latest_aj ON i.issue_id = latest_aj.issue_id AND latest_aj.rn = 1 WHERE i.worker_id = #{workerId}
AND i.status = #{status}
ORDER BY i.created_at DESC
